function UNIFY(x, y, θ):
 if θ = failure then return failure
 if x = y then return θ
 if VARIABLE(x) then return UNIFY-VAR(x, y, θ)
 if VARIABLE(y) then return UNIFY-VAR(y, x, θ)
 if COMPOUND(x) and COMPOUND(y) then
 return UNIFY(x.args, y.args, UNIFY(x.op, y.op, θ))
 if LIST(x) and LIST(y) then
 if empty(x) and empty(y) then return θ
 return UNIFY(rest(x), rest(y), UNIFY(first(x), first(y), θ))
 return failure

function UNIFY-VAR(var, term, θ):
 if {var/val} in θ then return UNIFY(val, term, θ)
 if {term/val} in θ then return UNIFY(var, val, θ)
 if var occurs in term then return failure // occurs check
 return θ ∪ {var/term}

