function RESOLUTION-REFUTE(KB, goal):
 // Step 1: Negate the goal
 clauses ← all clauses from KB
 add CLALSE(NOT(goal)) to clauses

 // Step 2: Apply resolution until empty clause or no progress
 new_clauses ← clauses

 while true:
 pairs ← all pairs of clauses in new_clauses
 resolvents ← empty

 for each pair (Ci, Cj) in pairs:
 resolvent ← RESOLVE(Ci, Cj)
 if resolvent = EMPTY-CLAUSE then
 return SUCCESS // Contradiction found
 if resolvent not in new_clauses then
 add resolvent to resolvents

 if resolvents is empty then
 return FAILURE // No more inferences possible

