function RESOLVE(Ci, Cj):
 // Find complementary literals
 for each literal Li in Ci:
 for each literal Lj in Cj:
 if COMPLEMENTARY(Li, Lj) then
 // Unify complementary literals
 mgu ← UNIFY(Li, NOT(Lj))
 if mgu ≠ failure then
 // Combine remaining literals
 return RESOLVENT(Ci, Cj, mgu)
 return failure // No resolution possible
